import freemarker.template.Configuration;
import freemarker.template.Template;
import freemarker.template.TemplateException;
import freemarker.template.TemplateExceptionHandler;
import org.apache.commons.lang3.StringUtils;

import java.io.IOException;
import java.io.StringWriter;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

/**
 * Template service class for handling user profile page template rendering
 */
public class TemplateService {

    private final Configuration freemarkerConfig;
    private final Map<String, Template> templateCache;
    private final StringTemplateLoader stringTemplateLoader;

    public TemplateService() {
        this.freemarkerConfig = new Configuration(Configuration.VERSION_2_3_31);
        this.freemarkerConfig.setClassLoaderForTemplateLoading(this.getClass().getClassLoader(), "/");
        this.freemarkerConfig.setDefaultEncoding("UTF-8");
        // Use a safer exception handler that doesn't expose internal details
        this.freemarkerConfig.setTemplateExceptionHandler(TemplateExceptionHandler.HTML_DEBUG_HANDLER);
        // Disable confusing built-ins for better user experience
        this.freemarkerConfig.setSharedVariable("new", new freemarker.template.utility.ObjectConstructor());

        this.templateCache = new ConcurrentHashMap<>();
        this.stringTemplateLoader = new StringTemplateLoader();
        this.freemarkerConfig.setTemplateLoader(stringTemplateLoader);
    }

    /**
     * Renders the user profile page based on username and template content
     * 
     * @param username the username
     * @param templateContent the user-provided template content
     * @return the rendered HTML string
     */
    public String renderUserProfile(String username, String templateContent) {
        if (StringUtils.isBlank(username)) {
            throw new IllegalArgumentException("Username cannot be empty");
        }
        if (StringUtils.isBlank(templateContent)) {
            throw new IllegalArgumentException("Template content cannot be empty");
        }

        try {
            // Use cached template or create new one
            String cacheKey = String.valueOf(templateContent.hashCode());
            Template template = templateCache.get(cacheKey);

            if (template == null) {
                // Store template content in the StringTemplateLoader
                stringTemplateLoader.putTemplate("userProfile", templateContent);
                template = freemarkerConfig.getTemplate("userProfile");

                // Cache the template for future use (with reasonable limit)
                if (templateCache.size() < 100) {
                    templateCache.put(cacheKey, template);
                }
            }

            // Prepare data model with username
            Map<String, Object> dataModel = new HashMap<>();
            dataModel.put("username", username);

            // Render template
            try (StringWriter writer = new StringWriter()) {
                template.process(dataModel, writer);
                return writer.toString();
            }

        } catch (IOException e) {
            throw new TemplateRenderingException("IO exception occurred during template processing: " + e.getMessage(), e);
        } catch (TemplateException e) {
            throw new TemplateRenderingException("Exception occurred during template rendering: " + e.getMessage(), e);
        }
    }

    /**
     * Custom exception for template rendering errors
     */
    public static class TemplateRenderingException extends RuntimeException {
        public TemplateRenderingException(String message) {
            super(message);
        }

        public TemplateRenderingException(String message, Throwable cause) {
            super(message, cause);
        }
    }
}

